import Cocoa

// Function to print errors to stderr
func printError(_ message: String) {
    if let data = "\(message)\n".data(using: .utf8) {
        FileHandle.standardError.write(data)
    }
}

func printDebug(_ message: String) {
    // Check if debugging is enabled via --debug or DEBUG_MODE environment variable
    let isDebugMode = CommandLine.arguments.contains("--debug") ||
                      ProcessInfo.processInfo.environment["DEBUG_MODE"] != nil

    if isDebugMode {
        if let data = "\(message)\n".data(using: .utf8) {
            FileHandle.standardError.write(data)
        }
    }
}

// Base64-encoded Homebrew SVG
let homebrewSvgBase64 = """

"""

// Base64-encoded Homebrew 256x256 PNG
let homebrewPngBase64 = """

"""

// Check for optional --debug flag
let isDebugMode = CommandLine.arguments.contains("--debug")

// Filter out the optional flags to isolate positional arguments
let positionalArgs = CommandLine.arguments.filter { !$0.hasPrefix("--") }

// Ensure exactly 2 positional arguments are provided: app_name, icon_choice
guard positionalArgs.count == 3 else {
    printError("Usage: quit_alert [--debug] <app_name> <icon_choice>")
    printError("<icon_choice>: 'brew' | 'mas' | <file_path>")
    exit(3) // General error
}

let appName = positionalArgs[1]
let iconChoice = positionalArgs[2]

// Validate the iconChoice argument
if iconChoice != "mas" && iconChoice != "brew" && !FileManager.default.fileExists(atPath: iconChoice) {
    printError("Invalid icon choice: '\(iconChoice)'")
    printError("Accepted values are: 'brew', 'mas', or a valid file path.")
    exit(3) // General error
}

// Create the alert
let alert = NSAlert()
alert.messageText = "\(appName) cannot be open during installation."
alert.informativeText = "Click Continue to quit \"\(appName)\" and begin the update. The application will open when the update is complete."
alert.alertStyle = .warning

// Determine icon based on choice
switch iconChoice {
case "mas":
    alert.icon = NSImage(byReferencingFile: "/System/Applications/App Store.app/Contents/Resources/AppIcon.icns")
    if let iconSize = alert.icon?.size {
        printDebug("Icon size being displayed: \(iconSize.width) × \(iconSize.height) pixels")
    }
case "brew":
    // Attempt to decode and render the SVG first
    if let svgData = Data(base64Encoded: homebrewSvgBase64),
       let homebrewSvgImage = NSImage(data: svgData) {
        printDebug("SVG decoding succeeded!")
        alert.icon = homebrewSvgImage
        if let iconSize = alert.icon?.size {
            printDebug("Homebrew SVG icon size being displayed: \(iconSize.width) × \(iconSize.height) pixels.")
        }
    } else if let pngData = Data(base64Encoded: homebrewPngBase64),
              let homebrewPngImage = NSImage(data: pngData) {
        // Fallback to PNG if SVG fails
        printDebug("SVG decoding failed. Falling back to PNG.")
        alert.icon = homebrewPngImage
        if let iconSize = alert.icon?.size {
            printDebug("Homebrew PNG icon size being displayed: \(iconSize.width) × \(iconSize.height) pixels.")
        }
    } else {
        // Handle complete failure gracefully
        printDebug("Both SVG and PNG decoding failed. Exiting with failure.")
        exit(2) // Icon load failure
    }
//    // Decode the Base64-encoded PNG and create an NSImage
//    if let pngData = Data(base64Encoded: homebrewPngBase64),
//       let homebrewImage = NSImage(data: pngData) {
//        printError("Base64 decoding succeeded!")
//        alert.icon = homebrewImage
//        if let iconSize = alert.icon?.size {
//            printError("Homebrew PNG icon size being displayed: \(iconSize.width) × \(iconSize.height) pixels.")
//        }
//    } else {
//        printError("Failed to decode Base64 PNG for Homebrew icon.")
//    }
default:
    alert.icon = NSImage(byReferencingFile: iconChoice)
    if let iconSize = alert.icon?.size {
        printDebug("Icon size being displayed: \(iconSize.width) × \(iconSize.height) pixels")
    }
}

// Add system-localized buttons
alert.addButton(withTitle: NSLocalizedString("Cancel", comment: ""))
alert.addButton(withTitle: NSLocalizedString("Continue", comment: ""))

// Run the dialog and handle the response
let response = alert.runModal()
exit(response == .alertSecondButtonReturn ? 0 : 1)
